/* SummaryDownload.css */

/* ── Page Title ── */
.summary-page-title {
    display: flex;
    align-items: center;
    gap: 12px;
    margin-bottom: 28px;
}

.summary-page-title .title-icon {
    width: 36px;
    height: 36px;
    background: #22c55e;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #fff;
}

/* ── Hero Banner ── */
.summary-hero {
    background: linear-gradient(135deg, #22c55e 0%, #16a34a 50%, #15803d 100%);
    border-radius: 20px;
    padding: 48px 40px;
    text-align: center;
    color: #fff;
    margin-bottom: 28px;
    position: relative;
    overflow: hidden;
}

.summary-hero::before,
.summary-hero::after {
    content: '';
    position: absolute;
    width: 200px;
    height: 200px;
    border-radius: 50%;
    background: rgba(255, 255, 255, 0.06);
}

.summary-hero::before {
    top: -60px;
    left: -60px;
}

.summary-hero::after {
    bottom: -80px;
    right: -40px;
    width: 260px;
    height: 260px;
}

.hero-check-circle {
    width: 72px;
    height: 72px;
    background: rgba(255, 255, 255, 0.2);
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    margin: 0 auto 20px;
    backdrop-filter: blur(4px);
}

.hero-check-circle svg {
    width: 36px;
    height: 36px;
}

.summary-hero h2 {
    font-size: 2rem;
    font-weight: 800;
    margin: 0 0 8px;
    letter-spacing: -0.02em;
}

.summary-hero p {
    font-size: 1.05rem;
    opacity: 0.9;
    margin: 0;
    font-weight: 500;
}

/* ── Stat Cards Row ── */
.summary-stats-row {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 20px;
    margin-bottom: 28px;
}

.summary-stat-card {
    background: #fff;
    border-radius: 16px;
    border: 1px solid #e2e8f0;
    padding: 28px 24px;
    text-align: center;
    box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.05);
    transition: transform 0.2s ease, box-shadow 0.2s ease;
    position: relative;
    overflow: hidden;
}

.summary-stat-card:hover {
    transform: translateY(-3px);
    box-shadow: 0 12px 20px -4px rgba(0, 0, 0, 0.1);
}

.summary-stat-card::before {
    content: '';
    position: absolute;
    left: 0;
    top: 0;
    bottom: 0;
    width: 4px;
}

.summary-stat-card.green::before {
    background: #22c55e;
}

.summary-stat-card.orange::before {
    background: #f97316;
}

.summary-stat-card.blue::before {
    background: #3b82f6;
}

.stat-card-icon {
    width: 48px;
    height: 48px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    margin: 0 auto 14px;
}

.stat-card-icon.green-bg {
    background: #dcfce7;
    color: #22c55e;
}

.stat-card-icon.orange-bg {
    background: #ffedd5;
    color: #f97316;
}

.stat-card-icon.blue-bg {
    background: #dbeafe;
    color: #3b82f6;
}

.summary-stat-card .stat-value {
    font-size: 2.5rem;
    font-weight: 800;
    margin: 0;
    line-height: 1.1;
}

.summary-stat-card .stat-value.green {
    color: #22c55e;
}

.summary-stat-card .stat-value.orange {
    color: #f97316;
}

.summary-stat-card .stat-value.blue {
    color: #3b82f6;
}

.summary-stat-card .stat-label {
    font-size: 0.75rem;
    font-weight: 700;
    color: #94a3b8;
    letter-spacing: 0.08em;
    text-transform: uppercase;
    margin-top: 6px;
}

/* ── Two Column: Progress + Improvements ── */
.summary-two-col {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 20px;
    margin-bottom: 28px;
}

.summary-card {
    background: #fff;
    border-radius: 16px;
    border: 1px solid #e2e8f0;
    padding: 28px;
    box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.05);
}

.summary-card h3 {
    font-size: 1.1rem;
    font-weight: 700;
    color: #1e293b;
    margin: 0 0 24px;
}

/* ── Circular Progress ── */
.progress-gauge-wrap {
    display: flex;
    flex-direction: column;
    align-items: center;
}

.progress-gauge {
    position: relative;
    width: 180px;
    height: 180px;
    margin-bottom: 16px;
}

.progress-gauge svg {
    transform: rotate(-90deg);
}

.progress-gauge-label {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    text-align: center;
}

.progress-gauge-label .gauge-value {
    font-size: 2.2rem;
    font-weight: 800;
    color: #1e293b;
    line-height: 1;
}

.progress-gauge-caption {
    font-size: 0.85rem;
    color: #64748b;
    margin-top: 4px;
}

/* ── Key Improvements ── */
.improvement-list {
    display: flex;
    flex-direction: column;
    gap: 14px;
}

.improvement-item {
    background: #f0fdf4;
    border-left: 4px solid #22c55e;
    border-radius: 0 12px 12px 0;
    padding: 16px 20px;
    transition: transform 0.15s ease;
}

.improvement-item:hover {
    transform: translateX(4px);
}

.improvement-item h4 {
    font-size: 0.95rem;
    font-weight: 700;
    color: #166534;
    margin: 0 0 4px;
}

.improvement-item p {
    font-size: 0.82rem;
    color: #4b5563;
    margin: 0;
    line-height: 1.5;
}

/* ── Action Bar ── */
.summary-action-bar {
    background: #fff;
    border-radius: 16px;
    border: 1px solid #e2e8f0;
    padding: 20px 28px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 28px;
    box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.05);
}

.action-bar-text {
    font-size: 0.95rem;
    color: #475569;
    font-weight: 500;
}

.action-bar-buttons {
    display: flex;
    gap: 14px;
}

.btn-rescan {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    padding: 12px 24px;
    border: 2px solid #e2e8f0;
    border-radius: 12px;
    background: #fff;
    color: #475569;
    font-weight: 600;
    font-size: 0.9rem;
    cursor: pointer;
    transition: all 0.2s ease;
}

.btn-rescan:hover {
    border-color: #3b82f6;
    color: #3b82f6;
    background: #eff6ff;
}

.btn-download {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    padding: 12px 28px;
    border: none;
    border-radius: 12px;
    background: linear-gradient(135deg, #4f46e5, #6366f1);
    color: #fff;
    font-weight: 600;
    font-size: 0.9rem;
    cursor: pointer;
    box-shadow: 0 4px 14px rgba(99, 102, 241, 0.35);
    transition: all 0.2s ease;
}

.btn-download:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 20px rgba(99, 102, 241, 0.45);
}

/* ── Detailed Change Log ── */
.summary-changelog {
    background: #fff;
    border-radius: 16px;
    border: 1px solid #e2e8f0;
    padding: 28px;
    box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.05);
}

.summary-changelog h3 {
    font-size: 1.1rem;
    font-weight: 700;
    color: #1e293b;
    margin: 0 0 20px;
}

.changelog-table {
    width: 100%;
    border-collapse: separate;
    border-spacing: 0;
}

.changelog-table thead th {
    background: #f8fafc;
    padding: 12px 16px;
    font-size: 0.72rem;
    font-weight: 700;
    color: #94a3b8;
    letter-spacing: 0.06em;
    text-transform: uppercase;
    text-align: left;
    border-bottom: 1px solid #e2e8f0;
}

.changelog-table thead th:first-child {
    border-radius: 10px 0 0 0;
}

.changelog-table thead th:last-child {
    border-radius: 0 10px 0 0;
}

.changelog-table tbody td {
    padding: 14px 16px;
    font-size: 0.88rem;
    color: #334155;
    border-bottom: 1px solid #f1f5f9;
}

.changelog-table tbody tr:hover {
    background: #f8fafc;
}

.changelog-table tbody tr:last-child td {
    border-bottom: none;
}

.fix-count-badge {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: 32px;
    padding: 4px 10px;
    border-radius: 100px;
    font-size: 0.8rem;
    font-weight: 700;
    background: #dcfce7;
    color: #166534;
}

/* ── Loading State ── */
.summary-loading {
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 60vh;
}

/* ── Responsive ── */
@media (max-width: 900px) {
    .summary-stats-row {
        grid-template-columns: 1fr;
    }

    .summary-two-col {
        grid-template-columns: 1fr;
    }

    .summary-action-bar {
        flex-direction: column;
        gap: 16px;
        text-align: center;
    }
}
